5	//#region src/stream.d.ts
6	/**
7	 * A React hook that provides seamless integration with LangGraph streaming capabilities.
8	 *
9	 * The `useStream` hook handles all the complexities of streaming, state management, and branching logic,
10	 * letting you focus on building great chat experiences. It provides automatic state management for
11	 * messages, interrupts, loading states, subagent streams, and errors.
12	 *
13	 * ## Usage with ReactAgent (recommended for createAgent users)
14	 *
15	 * When using `createAgent` from `@langchain/langgraph`, you can pass `typeof agent` as the
16	 * type parameter to automatically infer tool call types:
17	 *
18	 * @example
19	 * ```typescript
20	 * // In your agent file (e.g., agent.ts)
21	 * import { createAgent, tool } from "langchain";
22	 * import { z } from "zod";
23	 *
24	 * const getWeather = tool(
25	 *   async ({ location }) => `Weather in ${location}`,
26	 *   { name: "get_weather", schema: z.object({ location: z.string() }) }
27	 * );
28	 *
29	 * export const agent = createAgent({
30	 *   model: "openai:gpt-4o",
31	 *   tools: [getWeather],
32	 * });
33	 *
34	 * // In your React component
35	 * import { agent } from "./agent";
36	 *
37	 * function Chat() {
38	 *   // Tool calls are automatically typed from the agent's tools!
39	 *   const stream = useStream<typeof agent>({
40	 *     assistantId: "agent",
41	 *     apiUrl: "http://localhost:2024",
42	 *   });
43	 *
44	 *   // stream.toolCalls[0].call.name is typed as "get_weather"
45	 *   // stream.toolCalls[0].call.args is typed as { location: string }
46	 * }
47	 * ```
48	 *
49	 * ## Usage with StateGraph (for custom LangGraph applications)
50	 *
51	 * When building custom graphs with `StateGraph`, embed your tool call types directly
52	 * in your state's messages property using `Message<MyToolCalls>`:
53	 *
54	 * @example
55	 * ```typescript
56	 * import { Message } from "@langchain/langgraph-sdk";
57	 *
58	 * // Define your tool call types as a discriminated union
59	 * type MyToolCalls =
60	 *   | { name: "search"; args: { query: string }; id?: string }
61	 *   | { name: "calculate"; args: { expression: string }; id?: string };
62	 *
63	 * // Embed tool call types in your state's messages
64	 * interface MyGraphState {
65	 *   messages: Message<MyToolCalls>[];
66	 *   context?: string;
67	 * }
68	 *
69	 * function Chat() {
70	 *   const stream = useStream<MyGraphState>({
71	 *     assistantId: "my-graph",
72	 *     apiUrl: "http://localhost:2024",
73	 *   });
74	 *
75	 *   // stream.values is typed as MyGraphState
76	 *   // stream.toolCalls[0].call.name is typed as "search" | "calculate"
77	 * }
78	 * ```
79	 *
80	 * @example
81	 * ```typescript
82	 * // With additional type configuration (interrupts, configurable)
83	 * interface MyGraphState {
84	 *   messages: Message<MyToolCalls>[];
85	 * }
86	 *
87	 * function Chat() {
88	 *   const stream = useStream<MyGraphState, {
89	 *     InterruptType: { question: string };
90	 *     ConfigurableType: { userId: string };
91	 *   }>({
92	 *     assistantId: "my-graph",
93	 *     apiUrl: "http://localhost:2024",
94	 *   });
95	 *
96	 *   // stream.interrupt is typed as { question: string } | undefined
97	 * }
98	 * ```
99	 *
100	 * ## Usage with Deep Agents (subagent streaming, experimental)
101	 *
102	 * For agents that spawn subagents (nested graphs), use `filterSubagentMessages`
103	 * to keep the main message stream clean while tracking subagent activity separately:
104	 *
105	 * @example
106	 * ```typescript
107	 * import { useStream, SubagentStream } from "@langchain/langgraph-sdk/react";
108	 * import type { agent } from "./agent";
109	 *
110	 * function DeepAgentChat() {
