import { describe, it, expect } from "vitest";

// We test the internal extras validation to verify that values
// are properly included in the LangChainRuntimeExtras type.
// The hook itself uses React hooks and the store, so full integration
// testing would require setting up the full runtime.

const symbolLangChainRuntimeExtras = Symbol("langchain-runtime-extras");

type LangChainRuntimeExtras = {
  [symbolLangChainRuntimeExtras]: true;
  values: Record<string, unknown>;
  interrupt: { value?: unknown } | undefined;
  interrupts: readonly { value?: unknown }[];
  submit: (
    values: Record<string, unknown> | null | undefined,
    options?: Record<string, unknown>,
  ) => Promise<void>;
};

const asLangChainRuntimeExtras = (extras: unknown): LangChainRuntimeExtras => {
  if (
    typeof extras !== "object" ||
    extras == null ||
    !(symbolLangChainRuntimeExtras in extras)
  )
    throw new Error(
      "This method can only be called when you are using useStreamRuntime",
    );
  return extras as LangChainRuntimeExtras;
};

// Simulate what useLangChainState does
function simulateUseLangChainState<T>(
  extras: unknown,
  key: string,
  defaultValue?: T,
): T | undefined {
  if (!extras) return defaultValue;
  const { values } = asLangChainRuntimeExtras(extras);
  return (values[key] as T) ?? defaultValue;
}

describe("useLangChainState", () => {
  const validExtras = {
    [symbolLangChainRuntimeExtras]: true as const,
    values: {} as Record<string, unknown>,
    interrupt: undefined,
    interrupts: [],
    submit: async () => {},
  };

  it("returns undefined when no extras are provided", () => {
    const result = simulateUseLangChainState<string>(null, "todos");
    expect(result).toBeUndefined();
  });

  it("returns undefined when extras is null", () => {
    const result = simulateUseLangChainState<string>(null, "todos");
    expect(result).toBeUndefined();
  });

  it("returns default value when no extras are provided", () => {
    const result = simulateUseLangChainState<Todo[]>(null, "todos", []);
    expect(result).toEqual([]);
  });

  it("returns undefined for a key not present in values", () => {
    const result = simulateUseLangChainState<string>(validExtras, "todos");
    expect(result).toBeUndefined();
  });

  it("returns default value for a key not present in values", () => {
    const result = simulateUseLangChainState<Todo[]>(validExtras, "todos", []);
    expect(result).toEqual([]);
  });

  it("returns the value for a key present in values", () => {
    const todos: Todo[] = [
      { id: "1", title: "Buy groceries" },
      { id: "2", title: "Walk dog" },
    ];
    const extras = {
      ...validExtras,
      values: { todos },
    };
    const result = simulateUseLangChainState<Todo[]>(extras, "todos");
    expect(result).toEqual(todos);
  });

  it("returns the value for a key when default value is also provided", () => {
    const todos: Todo[] = [{ id: "1", title: "Read book" }];
    const extras = {
      ...validExtras,
      values: { todos },
    };
    const result = simulateUseLangChainState<Todo[]>(extras, "todos", []);
    expect(result).toEqual(todos);
  });

  it("returns defaultValue when value is explicitly undefined", () => {
    const extras = {
      ...validExtras,
      values: { todos: undefined },
    };
    const result = simulateUseLangChainState<Todo[]>(extras, "todos", []);
    expect(result).toEqual([]);
  });

  it("returns defaultValue when value is null", () => {
    const extras = {
      ...validExtras,
      values: { todos: null },
    };
    const result = simulateUseLangChainState<Todo[]>(extras, "todos", []);
    expect(result).toEqual([]);
  });

  it("returns the lastest updated value in values", () => {
    const initialTodos: Todo[] = [{ id: "1", title: "Initial" }];
    const updatedTodos: Todo[] = [
      { id: "1", title: "Initial" },
      { id: "2", title: "Updated" },
    ];

    let extras = {
      ...validExtras,
      values: { todos: initialTodos },
    };

    let result = simulateUseLangChainState<Todo[]>(extras, "todos");
    expect(result).toEqual(initialTodos);

    extras = {
      ...validExtras,
      values: { todos: updatedTodos },
    };

    result = simulateUseLangChainState<Todo[]>(extras, "todos");
    expect(result).toEqual(updatedTodos);
  });

  it("throws when extras are not valid LangChain runtime extras", () => {
    expect(() => {
      simulateUseLangChainState({}, "todos");
    }).toThrow("This method can only be called when you are using useStreamRuntime");
  });

  it("works with string values", () => {
    const extras = {
      ...validExtras,
      values: { status: "completed" },
    };
    const result = simulateUseLangChainState<string>(extras, "status");
    expect(result).toBe("completed");
  });

  it("works with number values", () => {
    const extras = {
      ...validExtras,
      values: { count: 42 },
    };
    const result = simulateUseLangChainState<number>(extras, "count");
    expect(result).toBe(42);
  });

  it("works with Record<string, string> values", () => {
    const files: Record<string, string> = { "/tmp/a.txt": "content a" };
    const extras = {
      ...validExtras,
      values: { files },
    };
    const result =
      simulateUseLangChainState<Record<string, string>>(extras, "files");
    expect(result).toEqual(files);
  });
});

type Todo = {
  id: string;
  title: string;
};

