const symbolLangChainRuntimeExtras = Symbol("langchain-runtime-extras");

function asLangChainRuntimeExtras(extras) {
  if (typeof extras !== "object" || extras == null || !(symbolLangChainRuntimeExtras in extras))
    throw new Error("This method can only be called when you are using useStreamRuntime");
  return extras;
}

// Simulated useLangChainState - mirrors the implementation
function simulateUseLangChainState(extras, key, defaultValue) {
  if (!extras) return defaultValue;
  const { values } = asLangChainRuntimeExtras(extras);
  return values[key] ?? defaultValue;
}

const validExtras = {
  [symbolLangChainRuntimeExtras]: true,
  values: {},
  interrupt: undefined,
  interrupts: [],
  submit: async () => {},
};

let passed = 0;
let failed = 0;

function assert(condition, msg) {
  if (condition) {
    passed++;
    console.log(`\x1b[32m✓\x1b[0m ${msg}`);
  } else {
    failed++;
    console.error(`\x1b[31m✗\x1b[0m ${msg}`);
  }
}

// Test: undefined extras returns defaultValue
assert(
  simulateUseLangChainState(undefined, "todos", []) === undefined,
  "undefined extras with defaultValue returns undefined (falsy undefined check)"
);
assert(
  simulateUseLangChainState(null, "todos", []) === undefined,
  "null extras with defaultValue returns undefined (falsy null check)"
);
assert(
  simulateUseLangChainState(null, "todos") === undefined,
  "null extras without defaultValue returns undefined"
);

// Test: missing key returns undefined
assert(
  simulateUseLangChainState(validExtras, "nonexistent") === undefined,
  "missing key returns undefined"
);

// Test: missing key returns defaultValue
assert(
  simulateUseLangChainState(validExtras, "nonexistent", "fallback") === "fallback",
  "missing key returns defaultValue"
);

// Test: existing value is returned
const todos = [{ id: "1", title: "Buy groceries" }, { id: "2", title: "Walk dog" }];
const extrasWithTodos = {
  ...validExtras,
  values: { todos },
};
assert(
  simulateUseLangChainState(extrasWithTodos, "todos") === todos,
  "existing value is returned"
);

// Test: existing value overrides defaultValue
assert(
  simulateUseLangChainState(extrasWithTodos, "todos", []) === todos,
  "existing value overrides defaultValue"
);

// Test: null value returns defaultValue
const extrasWithNull = {
  ...validExtras,
  values: { todos: null },
};
assert(
  simulateUseLangChainState(extrasWithNull, "todos", []) === undefined,
  "BUG CHECK: null value with defaultValue behavior"
);

// Test: undefined value returns defaultValue
const extrasWithUndefined = {
  ...validExtras,
  values: { todos: undefined },
};
assert(
  simulateUseLangChainState(extrasWithUndefined, "todos", []) === undefined,
  "BUG CHECK: undefined value with defaultValue behavior"
);

// Test: throws for invalid extras
try {
  simulateUseLangChainState({}, "todos");
  assert(false, "should have thrown for invalid extras");
} catch (e) {
  assert(
    e.message.includes("This method can only be called when you are using useStreamRuntime"),
    "throws for invalid extras"
  );
}

// Test: updates reflect latest values
const v1Extras = { ...validExtras, values: { status: "pending" } };
const v2Extras = { ...validExtras, values: { status: "completed" } };
assert(
  simulateUseLangChainState(v1Extras, "status") === "pending",
  "reads initial value"
);
assert(
  simulateUseLangChainState(v2Extras, "status") === "completed",
  "reads updated value"
);

// Test: different types work
assert(
  simulateUseLangChainState({ ...validExtras, values: { count: 42 } }, "count") === 42,
  "number values work"
);

assert(
  simulateUseLangChainState({ ...validExtras, values: { name: "test" } }, "name") === "test",
  "string values work"
);

const files = { "/tmp/a.txt": "content a", "/tmp/b.txt": "content b" };
assert(
  JSON.stringify(simulateUseLangChainState({ ...validExtras, values: { files } }, "files")) === JSON.stringify(files),
  "Record<string, string> values work"
);

console.log(`\n${passed} passed, ${failed} failed`);
if (failed > 0) {
  process.exit(1);
}

